43	////////////////////////////////////////////////////////////////////////////////////////////////////
44	/// TMA_LOAD : Initiates a TMA copy from global memory to shared memory
45	////////////////////////////////////////////////////////////////////////////////////////////////////
46	
47	struct SM90_TMA_LOAD_1D
48	{
49	  CUTE_HOST_DEVICE static void
50	  copy(void const* desc_ptr, uint64_t* mbar_ptr, uint64_t cache_hint,
51	       void      * smem_ptr,
52	       int32_t const& crd0)
53	  {
54	#if defined(CUTE_ARCH_TMA_SM90_ENABLED)
55	    uint64_t gmem_int_desc = reinterpret_cast<uint64_t>(desc_ptr);
