856	CUTE_HOST_DEVICE constexpr
857	void
858	fill_tma_gmem_shape_stride(Tensor<GEngine,GLayout>   const& gtensor,           // Gmem Shapes and Strides, in units of TmaInternalType
859	                           TmaGmemBasisStride        const& tma_gbasis_stride, // Map Tma mode idx -> Gmem mode(s)
860	                           cute::array<ShapeT,   TmaRank> & gmem_prob_shape,   // Tma Shapes, uint32_t or uin64_t
861	                           cute::array<uint64_t, TmaRank> & gmem_prob_stride)  // Tma Strides
862	{
863	  static_assert(is_tuple<TmaGmemBasisStride>::value);
864	  static_assert(is_same<uint32_t, ShapeT>::value || is_same<uint64_t, ShapeT>::value);
865	
866	  using TmaInternalType = typename GEngine::value_type;
867	  constexpr int tma_rank = decltype(rank(tma_gbasis_stride))::value;
868	  static_assert(TmaRank >= tma_rank);
869	
870	  auto gmem_shape  =  shape(gtensor);
871	  auto gmem_stride = stride(gtensor);
872	  // Use the indirections in tma_gbasis_stride into gtensor to construct the tma gmem shapes/strides
873	  for_each(make_seq<tma_rank>{}, [&](auto i) {
874	    constexpr int tma_i_rank = decltype(rank<i>(tma_gbasis_stride))::value;
875	    if constexpr (tma_i_rank == 1) {
876	      // Trivial contribution of this gmem mode to this tma mode
877	      auto ej = unwrap(get<i>(tma_gbasis_stride));
878	      gmem_prob_shape[i]  = basis_get(ej, gmem_shape);
879	      gmem_prob_stride[i] = basis_get(ej, gmem_stride);
880	    } else {
881	      // Apply a recurrence to each gmem mode that contributes to this tma mode
882	      for_each(get<i>(tma_gbasis_stride), [&](auto ej) {
883	        // Problem shape
884	        uint64_t shape_j  = basis_get(ej, gmem_shape);
885	        // Problem stride (in bytes)
886	        uint64_t stride_j = basis_get(ej, gmem_stride);
887	        uint64_t old_stride = gmem_prob_stride[i];
888	        gmem_prob_stride[i] = gcd(gmem_prob_stride[i], stride_j);
889	
890	        if (gmem_prob_stride[i] != 0) {
891	          // Recurrence: g_shape = (s_i - 1) * (d_i / gcd_j d_j) + 1
892	          gmem_prob_shape[i] = (gmem_prob_shape[i]-1) * (old_stride / gmem_prob_stride[i])
893	                             +            (shape_j-1) * (stride_j   / gmem_prob_stride[i])
894	                             + 1;
895	        } else {
896	          gmem_prob_shape[i] = shape_j;
897	        }
898	      });
899	    }
900	  });
901	}
